                        variant="outline"
                        className={cn(
                          "rounded-full px-2.5 py-0.5 text-[11px] font-medium",
                          item.score_delta >= 0
                            ? "border-emerald-200 bg-emerald-50 text-emerald-700"
                            : "border-rose-200 bg-rose-50 text-rose-700"
                        )}
                      >
                        {item.score_delta >= 0 ? "+" : ""}
                        {item.score_delta}
                      </Badge>
                    </div>

                    {item.extra_data ? (
                      <pre className="mt-3 overflow-x-auto rounded-xl bg-white px-3 py-2 text-xs text-slate-600">
                        {JSON.stringify(item.extra_data, null, 2)}
                      </pre>
                    ) : null}
                  </div>
                ))
              : null}
          </div>
        </div>

        <div className="flex flex-col gap-3 border-t border-slate-100 bg-slate-50/60 px-6 py-4 md:flex-row md:items-center md:justify-between">
          <p className="text-xs text-slate-500">
            {t("page", { current: currentPage, total: totalPages })}
          </p>

          <Pagination className="mx-0 w-auto justify-end">
            <PaginationContent className="gap-1">
              <PaginationItem>
                <PaginationPrevious
                  href="#"
                  text={t("prev")}
                  className={cn(
                    "h-8 rounded-lg px-3 text-xs",
                    currentPage === 1 && "pointer-events-none opacity-40"
                  )}
                  onClick={(event) => {
                    event.preventDefault()
                    if (currentPage > 1) onPageChange(currentPage - 1)
                  }}
                />
              </PaginationItem>

              {pageItems.map((page) => (
                <PaginationItem key={page}>
                  <PaginationLink
                    href="#"
                    isActive={page === currentPage}
                    className="h-8 w-8 rounded-lg text-xs"
                    onClick={(event) => {
                      event.preventDefault()
                      onPageChange(page)
                    }}
                  >
                    {page}
